#include <iostream>
using namespace std;

// Function to add two integers
int add(int a, int b) {
 cout << "Adding two ints: ";
 return a + b;
}

// Function to add two doubles
double add(double a, double b) {
 cout << "Adding two doubles: ";
 return a + b;
}

// Function to add three integers
int add(int a, int b, int c) {
 cout << "Adding three ints: ";
 return a + b + c;
}

int main() {
 cout << add(5, 10) << endl; // Calls int add(int, int)
 cout << add(3.5, 2.5) << endl; // Calls double add(double, double)
 cout << add(1, 2, 3) << endl; // Calls int add(int, int, int)
 return 0;
}

#include <iostream>
using namespace std;

void display(int &x) {
 cout << "Reference version: " << x << endl;
}

void display(const int &x) {
 cout << "Const reference version: " << x << endl;
}

void display(int x) {
 cout << "Value version: " << x << endl;
}

int main() {
 int a = 10;
 const int b = 20;

 display(a); // Calls non-const reference version
 display(b); // Calls const reference version
 display(30); // Calls value version (rvalue)
 return 0;
}

#include <iostream>
using namespace std;

// This causes ambiguity - cannot differentiate
void process(int x) {
 cout << "int version: " << x << endl;
}

void process(double x) {
 cout << "double version: " << x << endl;
}

// Uncommenting following causes ambiguity error:
// void test(int x, int y = 10) {}
// void test(int x) {}
// test(5); // Ambiguous!

int main() {
 // Ambiguity when both could match equally
 // process('a'); // Ambiguous - char promotes to both int and double

 // Explicit casting resolves ambiguity
 process(static_cast<int>('a'));
 process(static_cast<double>('a'));

 return 0;
}

#include <iostream>
using namespace std;

class Calculator {
public:
 // Add two integers
 int add(int a, int b) {
 return a + b;
 }

 // Add two doubles
 double add(double a, double b) {
 return a + b;
 }

 // Add three integers
 int add(int a, int b, int c) {
 return a + b + c;
 }

 // Concatenate strings
 string add(string s1, string s2) {
 return s1 + s2;
 }
};

int main() {
 Calculator calc;

 cout << calc.add(5, 10) << endl;
 cout << calc.add(3.5, 2.5) << endl;
 cout << calc.add(1, 2, 3) << endl;
 cout << calc.add("Hello ", "World!") << endl;

 return 0;
}
